changeSet.sql:
ALTER TABLE customer_personal_data ADD COLUMN IF NOT EXISTS fts_name TSVECTOR;
ALTER TABLE customer_org_data ADD COLUMN IF NOT EXISTS fts_name TSVECTOR;

UPDATE customer_personal_data
SET fts_name = to_tsvector('russian',
    coalesce(last_name, '') || ' ' ||
    coalesce(first_name, '') || ' ' ||
    coalesce(middle_name, ''));

UPDATE customer_org_data
SET fts_name = to_tsvector('russian', coalesce(org_name, ''));

CREATE INDEX IF NOT EXISTS idx_cpd_fts_name ON customer_personal_data USING GIN(fts_name);
CREATE INDEX IF NOT EXISTS idx_cod_fts_name ON customer_org_data USING GIN(fts_name);
